data.value:
decimal sumCobbPercentage = 0;
int validRowCount = 0;
decimal sumRossPercentage = 0;
int validRowCountRoss = 0;
decimal sumOtherPercentage = 0;
int validRowCountOther = 0;
decimal totalMort = 0;
decimal totalChickPlace = 0;
decimal totalCulls = 0;
decimal sumCumDepPercentage = 0;
int validRowCumDepCount = 0;
private void xrTableCell16_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Get Cobb and ChickPlace values
    decimal cobb = Convert.ToDecimal(GetCurrentColumnValue("Cobb") ?? 0);
    decimal chickPlace = Convert.ToDecimal(GetCurrentColumnValue("ChickPlace") ?? 0);

    if (chickPlace != 0)
    {
        // Calculate Cobb percentage
        decimal result = (cobb / chickPlace) * 100;
        cell.Text = result.ToString("N2") ;
    }
    else
    {
        cell.Text = "0.00";
    }

    }

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal cobb = Convert.ToDecimal(GetCurrentColumnValue("Cobb") ?? 0);
        decimal chickPlace = Convert.ToDecimal(GetCurrentColumnValue("ChickPlace") ?? 0);

        if (chickPlace != 0)
        {
            decimal percentage = (cobb / chickPlace) * 100;
            sumCobbPercentage += percentage;
            validRowCount++;
        }

        decimal ross = Convert.ToDecimal(GetCurrentColumnValue("Ross") ?? 0);

        if (chickPlace != 0)
        {
            decimal percentage = (ross / chickPlace) * 100;
            sumRossPercentage += percentage;
            validRowCountRoss++;
        }

         decimal other = Convert.ToDecimal(GetCurrentColumnValue("Other") ?? 0);

        if (chickPlace != 0)
        {
            decimal percentage = (other / chickPlace) * 100;
            sumOtherPercentage += percentage;
            validRowCountOther++;
        }

        // Sum each field separately
        totalMort += Convert.ToDecimal(GetCurrentColumnValue("Mort") ?? 0);
        totalChickPlace += Convert.ToDecimal(GetCurrentColumnValue("ChickPlace") ?? 0);
         totalCulls += Convert.ToDecimal(GetCurrentColumnValue("Culls") ?? 0);

        decimal cumTotalDep = Convert.ToDecimal(GetCurrentColumnValue("CumTotalDep") ?? 0);

        if (chickPlace > 0 && cumTotalDep > 0)
        {
            decimal percentage = (cumTotalDep / chickPlace) * 100;
            sumCumDepPercentage += percentage;
            validRowCumDepCount++;
        }

}

private void xrTableCell45_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

        if (validRowCount > 0)
        {
            decimal avg = sumCobbPercentage / validRowCount;
            cell.Text = avg.ToString("N2") ;
        }
        else
        {
            cell.Text = "0.00";
        }
}

