private void xrTableCell64_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

    // Get ChickPlace and CumTotalDep values
    decimal chickPlace = Convert.ToDecimal(GetCurrentColumnValue("ChickPlace") ?? 0);
    decimal cumTotalDep = Convert.ToDecimal(GetCurrentColumnValue("CumTotalDep") ?? 0);

    if (chickPlace > 0 && cumTotalDep > 0)
    {
        // Calculate cumulative depletion percentage
        decimal result = (cumTotalDep / chickPlace) * 100;
        cell.Text = result.ToString("N2");
    }
    else
    {
        cell.Text = "0.00";
    }
}

