private void xrTableCell96_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        XRTableCell cell = sender as XRTableCell;

    // Calculate total depletion (Mort + Culls)
    decimal totalDepletion = totalMort + totalCulls ;

    if (totalChickPlace > 0)
    {
        // Calculate total depletion percentage
        decimal result = (totalDepletion / totalChickPlace ) * 100;
        cell.Text = result.ToString("N2");
    }
    else
    {
        cell.Text = "0.00";
    }
}
